:root {
  --base-font-size: 1.125rem; /* 18px base font size */
  --base-line-height-factor: 1.6; /* A common line-height factor */
  /* The core unit for vertical rhythm, derived from body's line-height */
  --baseline-unit: calc(var(--base-font-size) * var(--base-line-height-factor)); /* Approx 28.8px */
}

body {
  font-family: 'Inter', sans-serif;
  font-size: var(--base-font-size);
  line-height: var(--base-line-height-factor);
}

/* Apply the baseline unit to vertical margins for consistent spacing */
h1, h2, h3, h4, h5, h6, p, ul, ol, blockquote, figure {
  margin-top: 0;
  margin-bottom: var(--baseline-unit); /* All elements get one baseline unit of space below */
}

/* Example for headings with different top margins, still multiples */
h1 {
  font-size: 2.5rem; /* ~40px */
  line-height: 1.2; /* Adjust line-height to fit content, but margins keep rhythm */
  margin-top: calc(var(--baseline-unit) * 2); /* 2 baseline units above H1 */
  margin-bottom: var(--baseline-unit); /* 1 baseline unit below H1 */
}

h2 {
  font-size: 1.75rem; /* ~28px */
  line-height: 1.3;
  margin-top: var(--baseline-unit); /* 1 baseline unit above H2 */
  margin-bottom: var(--baseline-unit);
}

/* For non-text elements like dividers or images */
.divider {
  height: 1px;
  background-color: #ccc;
  margin-top: var(--baseline-unit);
  margin-bottom: var(--baseline-unit);
}
